mapper.select:
/* 공지사항 일반 목록 조회 notice.selectNoticeListNormal */ SELECT NOTICE_ID , NOTICE_TYPE_CD , TITLE , PIN_YN , PIN_DT , VIEW_CNT , FEATURED_YN , USE_YN , CRTR_ID , CREATE_DT , MODIFY_DT FROM TB_NOTICE WHERE 1 = 1 AND USE_YN = 'Y' AND PIN_YN = 'N'
AND ( TITLE LIKE CONCAT('%', #{searchKeyword}, '%') OR CONTENT LIKE CONCAT('%', #{searchKeyword}, '%') )
AND NOTICE_TYPE_CD = #{noticeTypeCd}
ORDER BY CREATE_DT DESC
LIMIT #{firstIndex}, #{recordCountPerPage}

/* 공지사항 일반 목록 건수 조회 notice.selectNoticeListNormalCnt */ SELECT COUNT(1) FROM TB_NOTICE WHERE 1 = 1 AND USE_YN = 'Y' AND PIN_YN = 'N'
AND ( TITLE LIKE CONCAT('%', #{searchKeyword}, '%') OR CONTENT LIKE CONCAT('%', #{searchKeyword}, '%') )
AND NOTICE_TYPE_CD = #{noticeTypeCd}

/* 공지사항 고정 목록 조회 notice.selectNoticeListPinned */ SELECT NOTICE_ID , NOTICE_TYPE_CD , TITLE , PIN_YN , PIN_DT , VIEW_CNT , FEATURED_YN , USE_YN , CRTR_ID , CREATE_DT , MODIFY_DT FROM TB_NOTICE WHERE 1 = 1 AND USE_YN = 'Y' AND PIN_YN = 'Y'
AND ( TITLE LIKE CONCAT('%', #{searchKeyword}, '%') OR CONTENT LIKE CONCAT('%', #{searchKeyword}, '%') )
AND NOTICE_TYPE_CD = #{noticeTypeCd}
ORDER BY IFNULL(PIN_DT, CREATE_DT) DESC, CREATE_DT DESC

mapper.update:
/* 공지사항 조회수 증가 notice.updateNoticeViewCnt */
UPDATE TB_NOTICE
SET
    VIEW_CNT = VIEW_CNT + 1
WHERE NOTICE_ID = #{noticeId}

/* 대표 공지 초기화 notice.resetNoticeFeaturedYn */
UPDATE TB_NOTICE
SET
    FEATURED_YN = 'N'
WHERE FEATURED_YN = 'Y'

    AND NOTICE_ID != #{noticeId}

/* 고정 공지 5개 제한: 가장 오래된 PIN 해제 notice.resetOldestPinnedNotice */ UPDATE TB_NOTICE SET PIN_YN = 'N' , PIN_DT = NULL , MODIFY_DT = NOW() WHERE NOTICE_ID = ( SELECT T.NOTICE_ID FROM ( SELECT NOTICE_ID FROM TB_NOTICE WHERE 1 = 1 AND USE_YN = 'Y' AND PIN_YN = 'Y'
AND NOTICE_ID != #{noticeId}
ORDER BY IFNULL(PIN_DT, CREATE_DT) ASC, CREATE_DT ASC LIMIT 1 ) T ) AND ( SELECT CNT.C FROM ( SELECT COUNT(1) AS C FROM TB_NOTICE WHERE 1 = 1 AND USE_YN = 'Y' AND PIN_YN = 'Y'
AND NOTICE_ID != #{noticeId}
) AS CNT ) >= 5

/* 공지사항 삭제 notice.deleteNotice */
UPDATE TB_NOTICE
SET
    USE_YN = 'N'
    , MODIFY_DT = NOW()
WHERE NOTICE_ID = #{noticeId}
